CREATE TABLE "email_verification_tokens" (
  "id" serial PRIMARY KEY NOT NULL,
  "user_id" integer NOT NULL,
  "token" varchar(128) NOT NULL,
  "email" varchar(320) NOT NULL,
  "expires_at" timestamp with time zone NOT NULL,
  "used_at" timestamp with time zone,
  "created_at" timestamp with time zone DEFAULT now() NOT NULL,
  CONSTRAINT "email_verification_tokens_token_unique" UNIQUE("token")
);

ALTER TABLE "users" ADD COLUMN "email_verified" boolean DEFAULT false NOT NULL;

CREATE INDEX "idx_email_verification_tokens_token" ON "email_verification_tokens" USING btree ("token");
CREATE INDEX "idx_email_verification_tokens_user_id" ON "email_verification_tokens" USING btree ("user_id");

-- Mark existing users as verified (they signed up without verification)
UPDATE "users" SET "email_verified" = true WHERE "email_verified" = false;

